(() => {
  const htmx = {
    version: "local-shim-1.0",
    ajax(method, url, options = {}) {
      const headers = options.headers || {};
      const event = new CustomEvent("htmx:configRequest", { detail: { headers } });
      document.body.dispatchEvent(event);
      return fetch(url, { method, headers, body: options.body }).then(async (response) => {
        const text = await response.text();
        if (options.target) document.querySelector(options.target).innerHTML = text;
        return response;
      });
    },
  };
  window.htmx = htmx;
  document.addEventListener("click", (event) => {
    const element = event.target.closest("[hx-post],[hx-get]");
    if (!element) return;
    event.preventDefault();
    const method = element.hasAttribute("hx-post") ? "POST" : "GET";
    const url = element.getAttribute("hx-post") || element.getAttribute("hx-get");
    htmx.ajax(method, url, { target: element.getAttribute("hx-target") || null });
  });
})();
